// LocalNodeInfo is the resolver for the localNodeInfo field.
func (r *queryResolver) LocalNodeInfo(ctx context.Context) (*LocalNodeInfo, error) {
	head, headErr := r.HiveBlocks.GetLastProcessedBlock()
	if headErr != nil {
		return nil, headErr
	}
	election, electionErr := r.Elections.GetElectionByHeight(head)
	if electionErr != nil {
		return nil, electionErr
	}
	info := &LocalNodeInfo{
		GitCommit:          announcements.GitCommit,
		VersionID:          announcements.VersionId,
		LastProcessedBlock: model.Uint64(head),
		Epoch:              model.Uint64(election.Epoch),
		ChainOracles:       []ChainOracleStatus{},
	}
	if r.ChainOracle != nil {
		for _, cs := range r.ChainOracle.GetAllChainStatuses() {
			status := ChainOracleStatus{Symbol: cs.Symbol}
			if cs.BlockHeight != nil {
				h := model.Uint64(*cs.BlockHeight)
				status.BlockHeight = &h
			}
			info.ChainOracles = append(info.ChainOracles, status)
		}
	}
	return info, nil
}

